import os, re, sys, io
from collections import Counter
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')

# Count how many distinct source files reference each broken link target
link_sources = {}
all_sources = []
for root, dirs, files in os.walk('.'):
    for f in files:
        if not f.endswith('.md'):
            continue
        full = os.path.join(root, f)
        all_sources.append(full)

# Build set of existing basenames
existing = set()
for root, dirs, files in os.walk('.'):
    for f in files:
        if f.endswith('.md') and f not in ('index.md', 'log.md'):
            existing.add(f[:-3])

broken_targets = Counter()
broken_details = {}
for src in all_sources:
    with open(src, 'r', encoding='utf-8') as fh:
        content = fh.read()
    links = re.findall(r'\[\[([^\]|#]+?)(?:\|[^\]]*?)?(?:#[^\]]*?)?\]\]', content)
    for link in links:
        link = link.strip()
        if link.startswith('raw/'):
            continue
        link_bn = os.path.basename(link)
        if link_bn.endswith('.md'):
            link_bn = link_bn[:-3]
        if link_bn not in existing:
            broken_targets[link_bn] += 1
            broken_details.setdefault(link_bn, set()).add(src)

print('=== BROKEN LINK TARGETS (grouped by frequency) ===')
for target, count in broken_targets.most_common():
    sources = sorted(broken_details[target])
    src_names = [os.path.basename(s) for s in sources]
    eligible = '(eligible for page creation: 2+ sources)' if len(sources) >= 2 else ''
    print(f'  [[{target}]] - {len(sources)} source(s): {src_names} {eligible}')
